{
  "name": "client",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "tsc -b && vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1"
  },
  "devDependencies": {
    "@types/react": "^18.3.12",
    "@types/react-dom": "^18.3.1",
    "@vitejs/plugin-react": "^4.3.4",
    "typescript": "^5.8.3",
    "vite": "^6.3.5"
  }
}

import { FormEvent, useEffect, useMemo, useState } from "react";
import { api } from "./api";
import { Appointment, DashboardSummary, MessageLog, Service } from "./types";

const today = new Date().toISOString().slice(0, 10);

const timeLabel = (iso: string) =>
  new Intl.DateTimeFormat("es-ES", {
    dateStyle: "medium",
    timeStyle: "short",
    timeZone: "UTC"
  }).format(new Date(iso));

const statusLabel: Record<Appointment["status"], string> = {
  pending: "Pendiente",
  scheduled: "Programada",
  confirmed: "Confirmada",
  cancelled: "Cancelada",
  completed: "Completada",
  no_show: "No-show"
};

function App() {
  const [businessId, setBusinessId] = useState("");
  const [date, setDate] = useState(today);
  const [dashboard, setDashboard] = useState<DashboardSummary | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [appointmentForm, setAppointmentForm] = useState({
    contactId: "",
    serviceId: "",
    startAt: "",
    endAt: ""
  });
  const [simulateForm, setSimulateForm] = useState({
    fromPhone: "+34655566777",
    text: "Quiero cita"
  });
  const [calendarForm, setCalendarForm] = useState({
    googleCalendarConnected: false,
    googleCalendarId: "primary"
  });

  useEffect(() => {
    api
      .getBusinesses()
      .then((businesses) => {
        if (businesses[0]) {
          setBusinessId(businesses[0].id);
          setCalendarForm({
            googleCalendarConnected: businesses[0].googleCalendarConnected,
            googleCalendarId: businesses[0].googleCalendarId ?? "primary"
          });
        }
      })
      .catch((caughtError: Error) => setError(caughtError.message));
  }, []);

  const loadDashboard = async (selectedBusinessId: string, selectedDate: string) => {
    setLoading(true);
    setError(null);
    try {
      const data = await api.getDashboard(selectedBusinessId, selectedDate);
      setDashboard(data);
      setCalendarForm({
        googleCalendarConnected: data.business.googleCalendarConnected,
        googleCalendarId: data.business.googleCalendarId ?? "primary"
      });
      setAppointmentForm((current) => ({
        ...current,
        contactId: data.contacts[0]?.id ?? "",
        serviceId: data.services[0]?.id ?? ""
      }));
    } catch (caughtError) {
      setError(caughtError instanceof Error ? caughtError.message : "No se pudo cargar el dashboard");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (businessId) {
      void loadDashboard(businessId, date);
    }
  }, [businessId, date]);

  const contactsById = useMemo(
    () => new Map((dashboard?.contacts ?? []).map((contact) => [contact.id, contact])),
    [dashboard?.contacts]
  );
  const servicesById = useMemo(
    () => new Map((dashboard?.services ?? []).map((service) => [service.id, service])),
    [dashboard?.services]
  );

  const fillEndAt = (serviceId: string, startAt: string) => {
    if (!serviceId || !startAt) {
      return "";
    }

    const service = dashboard?.services.find((item) => item.id === serviceId);
    if (!service) {
      return "";
    }

    return new Date(new Date(startAt).getTime() + service.durationMinutes * 60 * 1000).toISOString();
  };

  const submitAppointment = async (event: FormEvent) => {
    event.preventDefault();
    if (!dashboard) {
      return;
    }

    const endAt = fillEndAt(appointmentForm.serviceId, appointmentForm.startAt);
    await api.createAppointment(dashboard.business.id, {
      ...appointmentForm,
      endAt,
      status: "scheduled",
      source: "manual"
    });
    await loadDashboard(dashboard.business.id, date);
  };

  const updateStatus = async (appointmentId: string, status: Appointment["status"]) => {
    if (!dashboard) {
      return;
    }
    await api.updateAppointment(dashboard.business.id, appointmentId, { status });
    await loadDashboard(dashboard.business.id, date);
  };

  const runAutomations = async () => {
    if (!dashboard) {
      return;
    }
    await api.processAutomations(dashboard.business.id);
    await loadDashboard(dashboard.business.id, date);
  };

  const simulateMessage = async (event: FormEvent) => {
    event.preventDefault();
    if (!dashboard) {
      return;
    }
    await api.simulateIncomingMessage(dashboard.business.id, simulateForm);
    await loadDashboard(dashboard.business.id, date);
  };

  const saveCalendar = async (event: FormEvent) => {
    event.preventDefault();
    if (!dashboard) {
      return;
    }
    await api.updateGoogleCalendar(dashboard.business.id, calendarForm);
    await loadDashboard(dashboard.business.id, date);
  };

  return (
    <div className="app-shell">
      <aside className="sidebar">
        <div>
          <p className="eyebrow">TarracoWebs</p>
          <h1>WhatsApp CRM</h1>
          <p className="muted">
            Agenda diaria, reseñas automáticas, anti no-show y captación de citas por WhatsApp.
          </p>
        </div>

        {dashboard && (
          <div className="panel tinted">
            <div className="stack-sm">
              <p className="eyebrow">Canal dedicado</p>
              <strong>{dashboard.channel?.displayName ?? "Sin canal"}</strong>
              <span className="muted">{dashboard.channel?.phoneE164 ?? "Pendiente de alta"}</span>
            </div>
            <div className="pill-row">
              <span className="pill">{dashboard.business.plan}</span>
              <span className="pill">{dashboard.business.city}</span>
            </div>
          </div>
        )}

        <div className="panel">
          <label className="field">
            <span>Fecha de agenda</span>
            <input type="date" value={date} onChange={(event) => setDate(event.target.value)} />
          </label>
          <button className="secondary" onClick={runAutomations} type="button">
            Procesar automatizaciones
          </button>
        </div>
      </aside>

      <main className="content">
        {error && <div className="error-banner">{error}</div>}
        {loading || !dashboard ? (
          <div className="loading-card">Cargando panel...</div>
        ) : (
          <>
            <section className="hero">
              <div>
                <p className="eyebrow">Negocio piloto</p>
                <h2>{dashboard.business.name}</h2>
                <p className="muted">
                  Canal propio por cliente, agenda compartida para los tres módulos y lista para integrarse con Google
                  Calendar.
                </p>
              </div>
              <div className="hero-actions">
                <button className="primary" type="button" onClick={() => setBusinessId(dashboard.business.id)}>
                  Panel activo
                </button>
                <span className="muted">{dashboard.business.email}</span>
              </div>
            </section>

            <section className="metrics-grid">
              <MetricCard label="Citas hoy" value={dashboard.metrics.todayAppointments} accent="sunrise" />
              <MetricCard label="Por confirmar" value={dashboard.metrics.pendingConfirmations} accent="ocean" />
              <MetricCard label="Reseñas pendientes" value={dashboard.metrics.reviewsPending} accent="moss" />
              <MetricCard label="Flujos abiertos" value={dashboard.metrics.whatsappOpenFlows} accent="wine" />
            </section>

            <section className="dashboard-grid">
              <div className="panel spacious">
                <div className="section-head">
                  <div>
                    <p className="eyebrow">Agenda del día</p>
                    <h3>Operativa clínica</h3>
                  </div>
                  <span className="muted">{dashboard.appointments.length} citas</span>
                </div>

                <div className="agenda-list">
                  {dashboard.appointments.map((appointment) => (
                    <article key={appointment.id} className="agenda-item">
                      <div>
                        <strong>{contactsById.get(appointment.contactId)?.name ?? "Paciente"}</strong>
                        <p className="muted">{servicesById.get(appointment.serviceId)?.name ?? "Servicio"}</p>
                        <p className="muted">{timeLabel(appointment.startAt)}</p>
                      </div>
                      <div className="agenda-actions">
                        <span className={`status-chip status-${appointment.status}`}>{statusLabel[appointment.status]}</span>
                        <div className="pill-row">
                          <button type="button" onClick={() => updateStatus(appointment.id, "confirmed")}>
                            Confirmar
                          </button>
                          <button type="button" onClick={() => updateStatus(appointment.id, "completed")}>
                            Completar
                          </button>
                          <button type="button" onClick={() => updateStatus(appointment.id, "cancelled")}>
                            Cancelar
                          </button>
                        </div>
                      </div>
                    </article>
                  ))}
                </div>
              </div>

              <div className="stack-lg">
                <div className="panel">
                  <div className="section-head">
                    <div>
                      <p className="eyebrow">Alta rápida</p>
                      <h3>Nueva cita manual</h3>
                    </div>
                  </div>
                  <form className="form-grid" onSubmit={submitAppointment}>
                    <label className="field">
                      <span>Paciente</span>
                      <select
                        value={appointmentForm.contactId}
                        onChange={(event) =>
                          setAppointmentForm((current) => ({ ...current, contactId: event.target.value }))
                        }
                      >
                        {dashboard.contacts.map((contact) => (
                          <option key={contact.id} value={contact.id}>
                            {contact.name}
                          </option>
                        ))}
                      </select>
                    </label>
                    <label className="field">
                      <span>Servicio</span>
                      <select
                        value={appointmentForm.serviceId}
                        onChange={(event) =>
                          setAppointmentForm((current) => ({ ...current, serviceId: event.target.value }))
                        }
                      >
                        {dashboard.services.map((service) => (
                          <option key={service.id} value={service.id}>
                            {service.name}
                          </option>
                        ))}
                      </select>
                    </label>
                    <label className="field">
                      <span>Inicio</span>
                      <input
                        type="datetime-local"
                        value={appointmentForm.startAt}
                        onChange={(event) =>
                          setAppointmentForm((current) => ({ ...current, startAt: new Date(event.target.value).toISOString() }))
                        }
                      />
                    </label>
                    <button className="primary" type="submit">
                      Guardar cita
                    </button>
                  </form>
                </div>

                <div className="panel">
                  <div className="section-head">
                    <div>
                      <p className="eyebrow">WhatsApp</p>
                      <h3>Simulador de conversación</h3>
                    </div>
                  </div>
                  <form className="form-grid" onSubmit={simulateMessage}>
                    <label className="field">
                      <span>Teléfono</span>
                      <input
                        value={simulateForm.fromPhone}
                        onChange={(event) => setSimulateForm((current) => ({ ...current, fromPhone: event.target.value }))}
                      />
                    </label>
                    <label className="field">
                      <span>Mensaje</span>
                      <input
                        value={simulateForm.text}
                        onChange={(event) => setSimulateForm((current) => ({ ...current, text: event.target.value }))}
                      />
                    </label>
                    <button className="primary" type="submit">
                      Enviar al flujo
                    </button>
                  </form>
                </div>

                <div className="panel">
                  <div className="section-head">
                    <div>
                      <p className="eyebrow">Google Calendar</p>
                      <h3>Preparación de integración</h3>
                    </div>
                    <span className={`status-chip ${dashboard.business.googleCalendarConnected ? "status-confirmed" : "status-pending"}`}>
                      {dashboard.business.googleCalendarConnected ? "Conectado" : "Pendiente"}
                    </span>
                  </div>
                  <form className="form-grid" onSubmit={saveCalendar}>
                    <label className="field checkbox">
                      <input
                        type="checkbox"
                        checked={calendarForm.googleCalendarConnected}
                        onChange={(event) =>
                          setCalendarForm((current) => ({
                            ...current,
                            googleCalendarConnected: event.target.checked
                          }))
                        }
                      />
                      <span>Activar sincronización</span>
                    </label>
                    <label className="field">
                      <span>Calendar ID</span>
                      <input
                        value={calendarForm.googleCalendarId}
                        onChange={(event) =>
                          setCalendarForm((current) => ({ ...current, googleCalendarId: event.target.value }))
                        }
                      />
                    </label>
                    <button className="secondary" type="submit">
                      Guardar configuración
                    </button>
                  </form>
                </div>
              </div>
            </section>

            <section className="dashboard-grid">
              <div className="panel spacious">
                <div className="section-head">
                  <div>
                    <p className="eyebrow">Mensajería</p>
                    <h3>Últimos mensajes</h3>
                  </div>
                </div>
                <div className="message-list">
                  {dashboard.recentMessages.map((message) => (
                    <MessageItem key={message.id} message={message} contactName={contactsById.get(message.contactId)?.name ?? "Paciente"} />
                  ))}
                </div>
              </div>

              <div className="panel spacious">
                <div className="section-head">
                  <div>
                    <p className="eyebrow">Servicios y reglas</p>
                    <h3>MVP acotado</h3>
                  </div>
                </div>
                <div className="service-list">
                  {dashboard.services.map((service) => (
                    <ServiceCard key={service.id} service={service} />
                  ))}
                </div>
                <div className="availability-grid">
                  {dashboard.availabilityRules.map((rule) => (
                    <div key={rule.id} className="rule-card">
                      <strong>Día {rule.weekday}</strong>
                      <span>
                        {rule.start} - {rule.end}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            </section>
          </>
        )}
      </main>
    </div>
  );
}

function MetricCard({ label, value, accent }: { label: string; value: number; accent: string }) {
  return (
    <div className={`metric-card ${accent}`}>
      <span>{label}</span>
      <strong>{value}</strong>
    </div>
  );
}

function MessageItem({ message, contactName }: { message: MessageLog; contactName: string }) {
  return (
    <article className={`message-item ${message.direction}`}>
      <div>
        <strong>{contactName}</strong>
        <p>{message.body}</p>
      </div>
      <span>{timeLabel(message.createdAt)}</span>
    </article>
  );
}

function ServiceCard({ service }: { service: Service }) {
  return (
    <article className="service-card">
      <strong>{service.name}</strong>
      <span>{service.durationMinutes} min</span>
    </article>
  );
}

export default App;

import { DashboardSummary, Appointment, Business } from "./types";

async function parseJson<T>(response: Response): Promise<T> {
  if (!response.ok) {
    const text = await response.text();
    throw new Error(text || "Request failed");
  }
  return response.json() as Promise<T>;
}

export const api = {
  getBusinesses: async () => parseJson<Business[]>(await fetch("/api/businesses")),
  getDashboard: async (businessId: string, date: string) =>
    parseJson<DashboardSummary>(await fetch(`/api/businesses/${businessId}/dashboard?date=${date}`)),
  createAppointment: async (businessId: string, body: Partial<Appointment>) =>
    parseJson<Appointment>(
      await fetch(`/api/businesses/${businessId}/appointments`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
      })
    ),
  updateAppointment: async (businessId: string, appointmentId: string, body: { status?: string; notes?: string }) =>
    parseJson<Appointment>(
      await fetch(`/api/businesses/${businessId}/appointments/${appointmentId}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
      })
    ),
  processAutomations: async (businessId: string) =>
    parseJson<{ ok: boolean }>(
      await fetch(`/api/businesses/${businessId}/automation/process-due`, {
        method: "POST"
      })
    ),
  simulateIncomingMessage: async (businessId: string, body: { fromPhone: string; text: string }) =>
    parseJson<{ action: string }>(
      await fetch(`/api/businesses/${businessId}/simulate-incoming-message`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
      })
    ),
  updateGoogleCalendar: async (businessId: string, body: { googleCalendarConnected: boolean; googleCalendarId: string }) =>
    parseJson<Business>(
      await fetch(`/api/businesses/${businessId}/google-calendar`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body)
      })
    )
};

import React from "react";
import ReactDOM from "react-dom/client";
import App from "./App";
import "./styles.css";

ReactDOM.createRoot(document.getElementById("root")!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

:root {
  font-family: "Segoe UI", "Helvetica Neue", sans-serif;
  color: #1f2a1e;
  background:
    radial-gradient(circle at top left, rgba(250, 182, 83, 0.3), transparent 28%),
    radial-gradient(circle at right 20%, rgba(36, 120, 108, 0.22), transparent 26%),
    linear-gradient(180deg, #f7f3e9 0%, #efe7d3 100%);
  --panel: rgba(255, 252, 247, 0.88);
  --panel-strong: rgba(255, 248, 235, 0.96);
  --line: rgba(56, 76, 58, 0.12);
  --text-soft: #5e6458;
  --accent: #1f6a60;
  --accent-2: #bb5f3f;
  --shadow: 0 18px 40px rgba(68, 57, 39, 0.12);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
}

button,
input,
select {
  font: inherit;
}

button {
  border: 0;
  border-radius: 999px;
  padding: 0.82rem 1.15rem;
  cursor: pointer;
  transition: transform 120ms ease, opacity 120ms ease;
}

button:hover {
  transform: translateY(-1px);
}

.primary {
  background: #1f6a60;
  color: #fff;
}

.secondary {
  background: rgba(31, 106, 96, 0.1);
  color: #1f6a60;
}

.app-shell {
  display: grid;
  grid-template-columns: 320px 1fr;
  min-height: 100vh;
}

.sidebar {
  padding: 2rem;
  border-right: 1px solid var(--line);
  background: rgba(255, 249, 238, 0.6);
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
  backdrop-filter: blur(16px);
}

.content {
  padding: 2rem;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}

.hero,
.panel,
.metric-card,
.loading-card,
.error-banner {
  border: 1px solid var(--line);
  box-shadow: var(--shadow);
}

.hero,
.panel,
.loading-card {
  background: var(--panel);
  border-radius: 28px;
}

.hero {
  display: flex;
  justify-content: space-between;
  gap: 1rem;
  padding: 1.6rem 1.8rem;
}

.panel {
  padding: 1.25rem;
}

.panel.spacious {
  padding: 1.5rem;
}

.panel.tinted {
  background: linear-gradient(180deg, rgba(36, 120, 108, 0.14), rgba(255, 248, 235, 0.9));
}

.loading-card,
.error-banner {
  padding: 1rem 1.2rem;
}

.error-banner {
  background: #fff2ec;
  border-radius: 20px;
  color: #8a3f28;
}

.eyebrow {
  margin: 0 0 0.35rem;
  text-transform: uppercase;
  letter-spacing: 0.12em;
  font-size: 0.72rem;
  color: var(--text-soft);
}

.muted {
  color: var(--text-soft);
}

.stack-sm,
.stack-lg,
.form-grid,
.message-list,
.service-list {
  display: grid;
  gap: 0.9rem;
}

.stack-lg {
  gap: 1.1rem;
}

.metrics-grid,
.dashboard-grid,
.availability-grid {
  display: grid;
  gap: 1rem;
}

.metrics-grid {
  grid-template-columns: repeat(4, minmax(0, 1fr));
}

.dashboard-grid {
  grid-template-columns: 1.45fr 1fr;
  align-items: start;
}

.availability-grid {
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.metric-card {
  padding: 1.2rem;
  border-radius: 24px;
  color: #fff;
  display: grid;
  gap: 0.35rem;
}

.metric-card strong {
  font-size: 2.2rem;
}

.metric-card.sunrise {
  background: linear-gradient(135deg, #d9784c, #f1ae63);
}

.metric-card.ocean {
  background: linear-gradient(135deg, #1f6a60, #4aa08f);
}

.metric-card.moss {
  background: linear-gradient(135deg, #516f3b, #9cb16f);
}

.metric-card.wine {
  background: linear-gradient(135deg, #6f3854, #c27f95);
}

.section-head,
.agenda-item,
.message-item,
.service-card,
.rule-card,
.field,
.hero-actions {
  display: flex;
}

.section-head,
.agenda-item,
.message-item {
  justify-content: space-between;
  gap: 1rem;
}

.agenda-list,
.message-list {
  display: grid;
  gap: 0.85rem;
}

.agenda-item,
.message-item,
.service-card,
.rule-card {
  padding: 1rem;
  border-radius: 22px;
  background: var(--panel-strong);
  border: 1px solid rgba(36, 120, 108, 0.09);
}

.agenda-actions,
.hero-actions {
  flex-direction: column;
  align-items: flex-end;
  gap: 0.65rem;
}

.field {
  flex-direction: column;
  gap: 0.35rem;
}

.field input,
.field select {
  border: 1px solid var(--line);
  border-radius: 16px;
  padding: 0.85rem 0.95rem;
  background: rgba(255, 255, 255, 0.75);
}

.field.checkbox {
  flex-direction: row;
  align-items: center;
}

.pill-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.pill,
.status-chip {
  border-radius: 999px;
  padding: 0.38rem 0.72rem;
  font-size: 0.82rem;
}

.pill {
  background: rgba(31, 106, 96, 0.08);
  color: #1f6a60;
}

.status-chip {
  background: rgba(95, 100, 88, 0.12);
  color: #44493f;
}

.status-confirmed {
  background: rgba(82, 140, 90, 0.18);
  color: #335436;
}

.status-scheduled,
.status-pending {
  background: rgba(214, 147, 52, 0.2);
  color: #7c5211;
}

.status-cancelled,
.status-no_show {
  background: rgba(168, 76, 63, 0.18);
  color: #7f3328;
}

.status-completed {
  background: rgba(31, 106, 96, 0.16);
  color: #1f6a60;
}

.message-item.incoming {
  border-left: 4px solid #bb5f3f;
}

.message-item.outgoing {
  border-left: 4px solid #1f6a60;
}

.service-list {
  grid-template-columns: repeat(3, minmax(0, 1fr));
}

.service-card,
.rule-card {
  flex-direction: column;
  gap: 0.4rem;
}

@media (max-width: 1080px) {
  .app-shell,
  .dashboard-grid,
  .metrics-grid,
  .service-list {
    grid-template-columns: 1fr;
  }

  .sidebar {
    border-right: 0;
    border-bottom: 1px solid var(--line);
  }
}

export type PlanCode = "reviews" | "anti_no_show" | "auto_appointments" | "full_pack";
export type AppointmentStatus = "pending" | "scheduled" | "confirmed" | "cancelled" | "completed" | "no_show";

export interface Business {
  id: string;
  name: string;
  email: string;
  phone: string;
  city: string;
  plan: PlanCode;
  googleReviewLink: string;
  active: boolean;
  createdAt: string;
  googleCalendarConnected: boolean;
  googleCalendarId?: string;
}

export interface Contact {
  id: string;
  businessId: string;
  name: string;
  phone: string;
  tags: string[];
  createdAt: string;
  lastInteractionAt?: string;
}

export interface Service {
  id: string;
  businessId: string;
  name: string;
  durationMinutes: number;
  active: boolean;
}

export interface AvailabilityRule {
  id: string;
  businessId: string;
  weekday: number;
  start: string;
  end: string;
}

export interface Appointment {
  id: string;
  businessId: string;
  contactId: string;
  serviceId: string;
  startAt: string;
  endAt: string;
  status: AppointmentStatus;
  source: "manual" | "whatsapp";
  notes?: string;
  googleCalendarEventId?: string;
  reviewRequestedAt?: string;
  reminderSentAt?: string;
  createdAt: string;
  updatedAt: string;
}

export interface MessageLog {
  id: string;
  businessId: string;
  contactId: string;
  direction: "incoming" | "outgoing";
  kind: "review_request" | "reminder" | "confirmation" | "assistant" | "human_handoff";
  body: string;
  appointmentId?: string;
  createdAt: string;
}

export interface DashboardSummary {
  business: Business;
  metrics: {
    todayAppointments: number;
    pendingConfirmations: number;
    completedAppointments: number;
    noShows: number;
    reviewsPending: number;
    whatsappOpenFlows: number;
  };
  appointments: Appointment[];
  contacts: Contact[];
  services: Service[];
  availabilityRules: AvailabilityRule[];
  recentMessages: MessageLog[];
  channel?: {
    phoneE164: string;
    phoneNumberId: string;
    displayName: string;
    templatesReady: boolean;
    active: boolean;
  };
}

